-- Insert 50 eccentric negative training exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Slow Eccentric Split Squat', 'slow-eccentric-split-squat', 'Slow Eccentric Split Squat is a slow negative/eccentric drill for front-leg quadriceps and hip control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.', 'BEGINNER', 8, 3, 5, 30, 75, 105, 'Slow Eccentric Split Squat builds front-leg quadriceps and hip control through a deliberate negative phase. Use it when the coach wants joint ownership, braking control, and local tissue capacity rather than speed or fatigue.', 'Primary subrole: Slow Eccentric / Isometric Joint Resilience. Coach 4-6 seconds lowering, pain-free range, clean alignment, and enough rest to preserve tissue quality. Specific focus: front-leg quadriceps and hip control.', 'Move slow, own the lowering, and stop before pain or compensation.', 'Split-stance eccentric control', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'split_stance_eccentric_control', '{"primary_joint_actions":["split_squat","eccentric_knee_flexion","hip_extension","ankle_dorsiflexion"],"primary_tissues":["quadriceps","glutes","hip_flexors","calves"],"primary_motor_control_demands":["slow_tempo_control","end_range_ownership","alignment_under_tension"],"postural_shape":"stacked_ribs_pelvis_and_controlled_joint_line","breathing_demand":"steady_nasal_or_controlled_exhale","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Slow Eccentric Split Squat is a slow negative/eccentric drill for front-leg quadriceps and hip control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.","setup":["Set a split stance with ribs stacked and front foot rooted.","Choose a load, range, height, or lever length that allows a smooth negative without pain.","Set the athlete''s start position before adding tempo or volume."],"execution_steps":["Create tension and start from a position the athlete can own.","Lower for 4-6 seconds, lightly touch the target depth, then stand with control.","Keep breathing controlled and avoid bouncing, dropping, twisting, or rushing the last third of the range.","Reset each rep so the next negative starts from the same clean position."],"coach_cues":["Slow is the load.","Own the last third.","Stop before compensation.","Quiet breath, quiet joints."],"common_faults":["Rushing the negative after the first half of the range.","Adding load before the athlete owns tempo and alignment.","Turning a tissue-control drill into a fatigue circuit.","Pushing through pain, joint pinch, or visible collapse."]}'::jsonb),
  ('Rear-Foot-Elevated Split Squat Negative', 'rear-foot-elevated-split-squat-negative', 'Rear-Foot-Elevated Split Squat Negative is a slow negative/eccentric drill for front-leg quadriceps, glutes, and pelvis control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.', 'INTERMEDIATE', 8, 3, 4, 24, 90, 114, 'Rear-Foot-Elevated Split Squat Negative builds front-leg quadriceps, glutes, and pelvis control through a deliberate negative phase. Use it when the coach wants joint ownership, braking control, and local tissue capacity rather than speed or fatigue.', 'Primary subrole: Slow Eccentric / Isometric Joint Resilience. Coach 4-6 seconds lowering, pain-free range, clean alignment, and enough rest to preserve tissue quality. Specific focus: front-leg quadriceps, glutes, and pelvis control.', 'Move slow, own the lowering, and stop before pain or compensation.', 'Rear-foot-elevated eccentric control', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'rear_foot_elevated_split_squat_negative', '{"primary_joint_actions":["rear_foot_elevated_split_squat","eccentric_knee_flexion","hip_extension","pelvis_control"],"primary_tissues":["quadriceps","glutes","adductors","hip_flexors"],"primary_motor_control_demands":["slow_tempo_control","end_range_ownership","alignment_under_tension"],"postural_shape":"stacked_ribs_pelvis_and_controlled_joint_line","breathing_demand":"steady_nasal_or_controlled_exhale","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Rear-Foot-Elevated Split Squat Negative is a slow negative/eccentric drill for front-leg quadriceps, glutes, and pelvis control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.","setup":["Place rear foot on a low bench or box; start with a shorter stance than a max-strength variation.","Choose a load, range, height, or lever length that allows a smooth negative without pain.","Set the athlete''s start position before adding tempo or volume."],"execution_steps":["Create tension and start from a position the athlete can own.","Lower for 4-6 seconds until the front leg reaches a controllable depth, then stand or assist out.","Keep breathing controlled and avoid bouncing, dropping, twisting, or rushing the last third of the range.","Reset each rep so the next negative starts from the same clean position."],"coach_cues":["Slow is the load.","Own the last third.","Stop before compensation.","Quiet breath, quiet joints."],"common_faults":["Rushing the negative after the first half of the range.","Adding load before the athlete owns tempo and alignment.","Turning a tissue-control drill into a fatigue circuit.","Pushing through pain, joint pinch, or visible collapse."]}'::jsonb),
  ('Eccentric Step-Down', 'eccentric-step-down', 'Eccentric Step-Down is a slow negative/eccentric drill for knee tracking and single-leg lowering control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.', 'BEGINNER', 8, 3, 5, 30, 75, 105, 'Eccentric Step-Down builds knee tracking and single-leg lowering control through a deliberate negative phase. Use it when the coach wants joint ownership, braking control, and local tissue capacity rather than speed or fatigue.', 'Primary subrole: Slow Eccentric / Isometric Joint Resilience. Coach 5 seconds lowering, pain-free range, clean alignment, and enough rest to preserve tissue quality. Specific focus: knee tracking and single-leg lowering control.', 'Move slow, own the lowering, and stop before pain or compensation.', 'Step-down knee control', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'step_down_eccentric_knee_control', '{"primary_joint_actions":["single_leg_step_down","eccentric_knee_flexion","hip_control","ankle_dorsiflexion"],"primary_tissues":["quadriceps","glutes","calves","foot_intrinsics"],"primary_motor_control_demands":["slow_tempo_control","end_range_ownership","alignment_under_tension"],"postural_shape":"stacked_ribs_pelvis_and_controlled_joint_line","breathing_demand":"steady_nasal_or_controlled_exhale","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Eccentric Step-Down is a slow negative/eccentric drill for knee tracking and single-leg lowering control. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.","setup":["Stand on a low box with one foot near the edge and the free heel hovering.","Choose a load, range, height, or lever length that allows a smooth negative without pain.","Set the athlete''s start position before adding tempo or volume."],"execution_steps":["Create tension and start from a position the athlete can own.","Reach the free heel toward the floor for 4-5 seconds, tap lightly, and return without pushing off the floor.","Keep breathing controlled and avoid bouncing, dropping, twisting, or rushing the last third of the range.","Reset each rep so the next negative starts from the same clean position."],"coach_cues":["Slow is the load.","Own the last third.","Stop before compensation.","Quiet breath, quiet joints."],"common_faults":["Rushing the negative after the first half of the range.","Adding load before the athlete owns tempo and alignment.","Turning a tissue-control drill into a fatigue circuit.","Pushing through pain, joint pinch, or visible collapse."]}'::jsonb),
  ('Slow Eccentric Goblet Squat', 'slow-eccentric-goblet-squat', 'Slow Eccentric Goblet Squat is a slow negative/eccentric drill for bilateral knee and hip lowering capacity. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.', 'BEGINNER', 8, 3, 5, 30, 90, 120, 'Slow Eccentric Goblet Squat builds bilateral knee and hip lowering capacity through a deliberate negative phase. Use it when the coach wants joint ownership, braking control, and local tissue capacity rather than speed or fatigue.', 'Primary subrole: Slow Eccentric / Isometric Joint Resilience. Coach 5 seconds lowering, pain-free range, clean alignment, and enough rest to preserve tissue quality. Specific focus: bilateral knee and hip lowering capacity.', 'Move slow, own the lowering, and stop before pain or compensation.', 'Bilateral squat tempo control', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'goblet_squat_slow_eccentric', '{"primary_joint_actions":["squat","eccentric_knee_flexion","hip_flexion","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors","spinal_erectors"],"primary_motor_control_demands":["slow_tempo_control","end_range_ownership","alignment_under_tension"],"postural_shape":"stacked_ribs_pelvis_and_controlled_joint_line","breathing_demand":"steady_nasal_or_controlled_exhale","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Slow Eccentric Goblet Squat is a slow negative/eccentric drill for bilateral knee and hip lowering capacity. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.","setup":["Hold a dumbbell in the goblet position with feet at squat width.","Choose a load, range, height, or lever length that allows a smooth negative without pain.","Set the athlete''s start position before adding tempo or volume."],"execution_steps":["Create tension and start from a position the athlete can own.","Descend for 5 seconds, pause briefly in the range you own, then stand without collapsing or bouncing.","Keep breathing controlled and avoid bouncing, dropping, twisting, or rushing the last third of the range.","Reset each rep so the next negative starts from the same clean position."],"coach_cues":["Slow is the load.","Own the last third.","Stop before compensation.","Quiet breath, quiet joints."],"common_faults":["Rushing the negative after the first half of the range.","Adding load before the athlete owns tempo and alignment.","Turning a tissue-control drill into a fatigue circuit.","Pushing through pain, joint pinch, or visible collapse."]}'::jsonb),
  ('Tempo Front Squat', 'tempo-front-squat', 'Tempo Front Squat is a slow negative/eccentric drill for front-rack squat control and quadriceps tissue capacity. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.', 'INTERMEDIATE', 8, 3, 3, 20, 120, 140, 'Tempo Front Squat builds front-rack squat control and quadriceps tissue capacity through a deliberate negative phase. Use it when the coach wants joint ownership, braking control, and local tissue capacity rather than speed or fatigue.', 'Primary subrole: Slow Eccentric / Isometric Joint Resilience. Coach 5 seconds lowering, pain-free range, clean alignment, and enough rest to preserve tissue quality. Specific focus: front-rack squat control and quadriceps tissue capacity.', 'Move slow, own the lowering, and stop before pain or compensation.', 'Loaded front-rack eccentric squat', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'tempo_front_squat_negative', '{"primary_joint_actions":["front_squat","eccentric_knee_flexion","front_rack_support","trunk_bracing"],"primary_tissues":["quadriceps","glutes","upper_back","core"],"primary_motor_control_demands":["slow_tempo_control","end_range_ownership","alignment_under_tension"],"postural_shape":"stacked_ribs_pelvis_and_controlled_joint_line","breathing_demand":"steady_nasal_or_controlled_exhale","balance_demand":"stable_to_moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Tempo Front Squat is a slow negative/eccentric drill for front-rack squat control and quadriceps tissue capacity. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.","setup":["Set a secure front rack from pins with a load the athlete can lower slowly.","Choose a load, range, height, or lever length that allows a smooth negative without pain.","Set the athlete''s start position before adding tempo or volume."],"execution_steps":["Create tension and start from a position the athlete can own.","Lower for 4-5 seconds, keep elbows high, and stand only if posture remains repeatable.","Keep breathing controlled and avoid bouncing, dropping, twisting, or rushing the last third of the range.","Reset each rep so the next negative starts from the same clean position."],"coach_cues":["Slow is the load.","Own the last third.","Stop before compensation.","Quiet breath, quiet joints."],"common_faults":["Rushing the negative after the first half of the range.","Adding load before the athlete owns tempo and alignment.","Turning a tissue-control drill into a fatigue circuit.","Pushing through pain, joint pinch, or visible collapse."]}'::jsonb),
  ('Spanish Squat 5-Second Lower', 'spanish-squat-5-second-lower', 'Spanish Squat 5-Second Lower is a slow negative/eccentric drill for quadriceps and patellar-tendon-friendly lowering. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.', 'BEGINNER', 8, 2, 6, 36, 75, 111, 'Spanish Squat 5-Second Lower builds quadriceps and patellar-tendon-friendly lowering through a deliberate negative phase. Use it when the coach wants joint ownership, braking control, and local tissue capacity rather than speed or fatigue.', 'Primary subrole: Slow Eccentric / Isometric Joint Resilience. Coach 5 seconds lowering, pain-free range, clean alignment, and enough rest to preserve tissue quality. Specific focus: quadriceps and patellar-tendon-friendly lowering.', 'Move slow, own the lowering, and stop before pain or compensation.', 'Supported knee-dominant eccentric', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'spanish_squat_five_second_lower', '{"primary_joint_actions":["supported_squat","eccentric_knee_flexion","trunk_bracing"],"primary_tissues":["quadriceps","patellar_tendon","glutes"],"primary_motor_control_demands":["slow_tempo_control","end_range_ownership","alignment_under_tension"],"postural_shape":"stacked_ribs_pelvis_and_controlled_joint_line","breathing_demand":"steady_nasal_or_controlled_exhale","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Spanish Squat 5-Second Lower is a slow negative/eccentric drill for quadriceps and patellar-tendon-friendly lowering. It uses deliberate lowering, clean alignment, and enough rest to build control and tissue capacity without chasing fatigue.","setup":["Anchor a thick band behind the knees and sit back against it with feet planted.","Choose a load, range, height, or lever length that allows a smooth negative without pain.","Set the athlete''s start position before adding tempo 