  ('tempo-front-squat', 'resilience', 'tempo_front_squat_negative', 5, FALSE, 3, 3, 4, 0, 'moderate'),
  ('spanish-squat-5-second-lower', 'resilience', 'spanish_squat_five_second_lower', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('slow-cossack-squat-shift', 'resilience', 'slow_cossack_squat_shift', 5, FALSE, 3, 3, 4, 0, 'moderate'),
  ('lateral-lunge-negative', 'resilience', 'lateral_lunge_negative', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('reverse-lunge-negative', 'resilience', 'reverse_lunge_negative', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('single-leg-box-squat-negative', 'resilience', 'single_leg_box_squat_negative', 5, FALSE, 3, 3, 4, 0, 'moderate'),
  ('nordic-hamstring-curl-negative', 'resilience', 'nordic_hamstring_curl_negative', 5, FALSE, 4, 4, 4, 0, 'high'),
  ('razor-curl-negative', 'resilience', 'razor_curl_negative', 5, FALSE, 4, 4, 5, 0, 'high'),
  ('sliding-hamstring-curl-eccentric', 'resilience', 'sliding_hamstring_curl_eccentric', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('romanian-deadlift-eccentric', 'resilience', 'romanian_deadlift_eccentric', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('single-leg-rdl-negative', 'resilience', 'single_leg_rdl_negative', 5, FALSE, 3, 3, 4, 0, 'moderate'),
  ('hip-thrust-eccentric-lower', 'resilience', 'hip_thrust_eccentric_lower', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('copenhagen-adduction-negative', 'resilience', 'copenhagen_adduction_negative', 5, FALSE, 4, 4, 4, 0, 'high'),
  ('standing-calf-raise-eccentric-lower', 'resilience', 'standing_calf_raise_eccentric_lower', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('seated-soleus-raise-eccentric', 'resilience', 'seated_soleus_raise_eccentric', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('tibialis-raise-eccentric-lower', 'resilience', 'tibialis_raise_eccentric_lower', 5, FALSE, 3, 2, 1, 0, 'moderate'),
  ('negative-pull-up', 'resilience', 'negative_pull_up', 5, FALSE, 3, 3, 4, 0, 'moderate'),
  ('negative-chin-up', 'resilience', 'negative_chin_up', 5, FALSE, 3, 3, 4, 0, 'moderate'),
  ('inverted-row-negative', 'resilience', 'inverted_row_negative', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('ring-row-eccentric', 'resilience', 'ring_row_eccentric', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('push-up-negative', 'resilience', 'push_up_negative', 5, FALSE, 3, 3, 2, 0, 'moderate'),
