  ('wall-handstand-negative-to-box', 'resilience', 'wall_handstand_negative_to_box', 5, FALSE, 4, 4, 5, 0, 'high'),
  ('dumbbell-bench-press-eccentric', 'resilience', 'dumbbell_bench_press_eccentric', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('dumbbell-overhead-press-eccentric', 'resilience', 'dumbbell_overhead_press_eccentric', 5, FALSE, 3, 3, 3, 0, 'moderate'),
