  ('pallof-press-eccentric-return', 'resilience', 'pallof_press_eccentric_return', 5, FALSE, 3, 2, 2, 0, 'moderate'),
  ('medicine-ball-catch-to-absorb-hold', 'resilience', 'medicine_ball_catch_to_absorb_hold', 5, FALSE, 3, 3, 3, 1, 'moderate'),
  ('low-box-drop-to-eccentric-landing-stick', 'resilience', 'low_box_drop_eccentric_landing_stick', 5, FALSE, 3, 3, 3, 2, 'moderate'),
  ('linear-deceleration-stop-eccentric-stick', 'resilience', 'linear_deceleration_stop_eccentric_stick', 5, FALSE, 3, 3, 4, 1, 'moderate'),
  ('lateral-step-off-to-eccentric-stick', 'resilience', 'lateral_step_off_eccentric_stick', 5, FALSE, 3, 3, 4, 2, 'moderate'),
  ('tempo-deadlift-lower', 'resilience', 'tempo_deadlift_lower', 5, FALSE, 4, 4, 4, 0, 'high'),
  ('tempo-back-squat-5-second-lower', 'resilience', 'tempo_back_squat_five_second_lower', 5, FALSE, 4, 4, 4, 0, 'high'),
  ('tempo-bench-press-5-second-lower', 'resilience', 'tempo_bench_press_five_second_lower', 5, FALSE, 4, 4, 4, 0, 'high'),
  ('tempo-dumbbell-row-negative', 'resilience', 'tempo_dumbbell_row_negative', 5, FALSE, 3, 3, 3, 0, 'moderate'),
  ('tempo-lat-pulldown-negative', 'resilience', 'tempo_lat_pulldown_negative', 5, FALSE, 3, 3, 2, 0, 'moderate'),
  ('slow-eccentric-cable-row', 'resilience', 'slow_eccentric_cable_row', 5, FALSE, 3, 3, 2, 0, 'moderate'),
